23	// DesiredRef describes a single ref we want to fetch from source.
24	type DesiredRef struct {
25		SourceRef  plumbing.ReferenceName
26		TargetRef  plumbing.ReferenceName
27		SourceHash plumbing.Hash
28		IsTag      bool
29	}
