31	// FetchFeatures summarizes negotiated source fetch features used by strategies.
32	type FetchFeatures struct {
33		Filter     bool
34		IncludeTag bool
35	}
36	
37	func (s *RefService) FetchFeatures() FetchFeatures {
38		if s == nil || s.Protocol != "v2" || s.V2Caps == nil {
39			return FetchFeatures{}
40		}
41		return FetchFeatures{
42			Filter:     s.V2Caps.FetchSupports("filter"),
43			IncludeTag: s.V2Caps.FetchSupports("include-tag"),
44		}
45	}
46	
47	// SupportsBootstrapBatch centralizes the source-side capability check for the
48	// batched bootstrap strategy.
49	func (s *RefService) SupportsBootstrapBatch() bool {
50		return s != nil && s.Protocol == "v2" && s.FetchFeatures().Filter
51	}
52	
53	// FetchToStore fetches objects from source into the given store, using the
54	// appropriate protocol version.
55	func (s *RefService) FetchToStore(
56		ctx context.Context,
57		store storer.Storer,
58		conn Conn,
59		desired map[plumbing.ReferenceName]DesiredRef,
60		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
61	) error {
62		var err error
63		switch s.Protocol {
64		case "v2":
65			err = fetchToStoreV2(ctx, store, conn, s.V2Caps, desired, targetRefs, s.Verbose)
66		case "v1":
67			err = fetchToStoreV1(ctx, store, conn, s.V1Adv, desired, targetRefs, s.Verbose)
68		default:
69			return fmt.Errorf("unsupported source protocol %q", s.Protocol)
70		}
71		// If the context was canceled, surface that as the primary error — any
72		// downstream parse/network failure is a side effect of cancellation and
73		// would race with ctx.Err() depending on read timing.
74		if err != nil && ctx.Err() != nil {
75			return errors.Join(ctx.Err(), err)
76		}
77		return err
78	}
