169			"want "+ref.SourceHash.String(),
170		)
171		for _, h := range sortedHaves {
172			cmdArgs = append(cmdArgs, "have "+h.String())
173		}
174		cmdArgs = append(cmdArgs, "done")
175	
176		body, err := EncodeCommand("fetch", s.V2Caps.RequestCapabilities(), cmdArgs)
177		if err != nil {
178			return nil, err
179		}
180		reader, err := PostRPCStream(ctx, conn, transport.UploadPackService, body, true, "upload-pack fetch")
181		if err != nil {
182			return nil, err
183		}
184		defer ioutil.CheckClose(reader, &err)
185	
186		parents = map[plumbing.Hash][]plumbing.Hash{}
187		consumeErr := consumeV2FetchPack(reader, false, nil, func(packReader io.Reader) error {
188			got, perr := ExtractCommitParents(packReader)
189			if perr != nil {
190				return perr
191			}
192			parents = got
193			return nil
194		})
195		if consumeErr != nil {
196			return nil, consumeErr
197		}
198		return parents, nil
