259	func fetchPackV2(
260		ctx context.Context,
261		conn Conn,
262		caps *V2Capabilities,
263		desired map[plumbing.ReferenceName]DesiredRef,
264		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
265		verbose bool,
266	) (io.ReadCloser, error) {
267		wants := collectWants(desired)
268		haves := SortedUniqueHashes(refValues(targetRefs))
269		if len(wants) == 0 {
270			return nil, git.NoErrAlreadyUpToDate
271		}
272	
273		cmdArgs := make([]string, 0, len(wants)+len(haves)+4)
274		// NOTE: no "thin-pack" argument. The relayed pack must stay
275		// self-contained so callers (e.g. replicate) can forward it to
276		// receive-pack servers that may advertise "no-thin". See
277		// planner.SupportsReplicateRelay for the matching invariant.
278		cmdArgs = append(cmdArgs, "ofs-delta")
279		if !verbose {
280			cmdArgs = append(cmdArgs, "no-progress")
281		}
282		// Only request include-tag if the server supports it (issue #6).
283		if hasTag(desired) && caps.FetchSupports("include-tag") {
284			cmdArgs = append(cmdArgs, "include-tag")
285		}
286		for _, h := range wants {
287			cmdArgs = append(cmdArgs, "want "+h.String())
288		}
289		for _, h := range haves {
290			cmdArgs = append(cmdArgs, "have "+h.String())
291		}
292		cmdArgs = append(cmdArgs, "done")
293	
294		body, err := EncodeCommand("fetch", caps.RequestCapabilities(), cmdArgs)
295		if err != nil {
296			return nil, err
297		}
298		reader, err := PostRPCStream(ctx, conn, transport.UploadPackService, body, true, "upload-pack fetch")
299		if err != nil {
300			return nil, err
301		}
302		packStream, err := openV2PackStream(reader, verbose, conn.ProgressWriter())
303		if err != nil {
304			_ = reader.Close()
305			return nil, err
306		}
307		return packStream, nil
308	}
