310	func storeV2FetchPack(store storer.Storer, r io.Reader, verbose bool, progressOut io.Writer) error {
311		return consumeV2FetchPack(r, verbose, progressOut, func(packReader io.Reader) error {
312			if err := packfile.UpdateObjectStorage(store, packReader); err != nil {
313				return fmt.Errorf("update object storage: %w", err)
314			}
315			return nil
316		})
317	}
318	
319	// consumeV2FetchPack walks a protocol v2 fetch response envelope
320	// (acknowledgments / shallow-info / packfile sections) and hands the
321	// demuxed packfile stream to consumer when one is present. Returns nil
322	// for empty / no-pack responses without invoking consumer.
323	func consumeV2FetchPack(
324		r io.Reader,
325		verbose bool,
326		progressOut io.Writer,
327		consumer func(io.Reader) error,
328	) error {
329		reader := NewPacketReader(r)
330		expectPackfile := false
331		for {
332			kind, payload, err := reader.ReadPacket()
333			if err != nil {
334				if errors.Is(err, io.EOF) {
335					if expectPackfile {
336						return errors.New("expected packfile to be sent after 'ready'")
337					}
338					return nil
339				}
340				return fmt.Errorf("decode protocol v2 fetch response: %w", err)
341			}
342			switch kind {
343			case PacketFlush:
344				if expectPackfile {
345					return errors.New("expected packfile to be sent after 'ready'")
346				}
347				return nil
348			case PacketDelim, PacketResponseEnd:
349				continue
350			case PacketData:
351				line := string(payload)
352				if strings.HasPrefix(line, "ERR ") {
353					return errors.New("remote: " + line[4:])
354				}
355				switch line {
356				case "packfile\n":
357					demux := sideband.NewDemuxer(sideband.Sideband64k, reader.BufReader())
358					demux.Progress = progressSink(verbose, "source: ", progressOut)
359					return consumer(demux)
360				case "acknowledgments\n":
361					ready, err := skipV2Acknowledgments(reader)
362					if err != nil {
363						return err
364					}
365					expectPackfile = ready
366				case "shallow-info\n":
367					expectPackfile = true
368					if err := SkipSection(reader); err != nil {
369						return err
370					}
371				default:
372					return fmt.Errorf("unexpected protocol v2 fetch section %q", strings.TrimSpace(line))
373				}
374			}
375		}
376	}
377	
378	func openV2PackStream(body io.ReadCloser, verbose bool, progressOut io.Writer) (io.ReadCloser, error) {
379		reader := NewPacketReader(body)
380		for {
381			kind, payload, err := reader.ReadPacket()
382			if err != nil {
383				if errors.Is(err, io.EOF) {
384					return nil, io.ErrUnexpectedEOF
385				}
386				return nil, fmt.Errorf("decode protocol v2 fetch response: %w", err)
387			}
388			switch kind {
389			case PacketFlush:
390				return nil, io.ErrUnexpectedEOF
391			case PacketDelim, PacketResponseEnd:
392				continue
393			case PacketData:
394				line := string(payload)
395				if strings.HasPrefix(line, "ERR ") {
396					return nil, errors.New("remote: " + line[4:])
397				}
398				switch line {
399				case "packfile\n":
400					demux := sideband.NewDemuxer(sideband.Sideband64k, reader.BufReader())
401					demux.Progress = progressSink(verbose, "source: ", progressOut)
402					return &wrappedRC{
403						Reader: demux,
404						Closer: body,
405					}, nil
406				case "acknowledgments\n":
407					if _, err := skipV2Acknowledgments(reader); err != nil {
408						return nil, err
409					}
410				case "shallow-info\n":
411					if err := SkipSection(reader); err != nil {
412						return nil, err
413					}
414				default:
415					return nil, fmt.Errorf("unexpected protocol v2 fetch section %q", strings.TrimSpace(line))
416				}
417			}
418		}
419	}
420	
421	func skipV2Acknowledgments(reader *PacketReader) (bool, error) {
422		ready := false
423		for {
424			kind, payload, err := reader.ReadPacket()
425			if err != nil {
426				return false, err
427			}
428			switch kind {
429			case PacketFlush:
430				if ready {
431					return false, errors.New("expected packfile to be sent after 'ready'")
432				}
433				return false, errors.New("protocol v2 fetch response ended without packfile after acknowledgments")
434			case PacketDelim:
435				if !ready {
436					return false, errors.New("unexpected delimiter in acknowledgments section without 'ready'")
437				}
438				return true, nil
439			case PacketData:
440				line := string(payload)
441				switch {
442				case line == "NAK\n", strings.HasPrefix(line, "ACK "):
443					continue
444				case line == "ready\n":
445					ready = true
446				default:
447					return false, fmt.Errorf("unexpected acknowledgment line %q", strings.TrimSpace(line))
448				}
449			case PacketResponseEnd:
450				return false, fmt.Errorf("unexpected packet type %v in acknowledgments section", kind)
451			default:
452				return false, fmt.Errorf("unexpected packet type %v in acknowledgments section", kind)
453			}
454		}
455	}
