458	
459	// buildV1UploadPackBody encodes a v1 upload-pack request body for stateless-rpc HTTP.
460	func buildV1UploadPackBody(
461		adv *packp.AdvRefs,
462		desired map[plumbing.ReferenceName]DesiredRef,
463		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
464		includeTags bool,
465		verbose bool,
466	) ([]byte, *capability.List, error) {
467		wants := collectWants(desired)
468		haves := SortedUniqueHashes(refValues(targetRefs))
469		if len(wants) == 0 {
470			return nil, nil, git.NoErrAlreadyUpToDate
471		}
472	
473		req := &packp.UploadRequest{}
474		req.Wants = wants
475		if !verbose && adv.Capabilities.Supports(capability.NoProgress) {
476			req.Capabilities.Set(capability.NoProgress)
477		}
478		if includeTags && adv.Capabilities.Supports(capability.IncludeTag) {
479			req.Capabilities.Set(capability.IncludeTag)
480		}
481		// Prefer sideband64k over sideband (issue #4).
482		if sb := PreferredSideband(&adv.Capabilities); sb != "" {
483			req.Capabilities.Set(sb)
484		}
485		if adv.Capabilities.Supports(capability.OFSDelta) {
486			req.Capabilities.Set(capability.OFSDelta)
487		}
488		// NOTE: we intentionally do not request capability.ThinPack. The relayed
489		// pack must stay self-contained because callers (e.g. replicate) forward
490		// it to receive-pack servers that may advertise "no-thin".
491		// planner.SupportsReplicateRelay depends on this invariant — if you add
492		// thin-pack support here, update that check to gate on target NoThin.
493	
494		var buf bytes.Buffer
495		if err := req.Encode(&buf); err != nil {
496			return nil, nil, fmt.Errorf("encode upload-request: %w", err)
497		}
498		uphav := &packp.UploadHaves{Haves: haves, Done: true}
499		if err := uphav.Encode(&buf); err != nil {
500			return nil, nil, fmt.Errorf("encode upload-haves: %w", err)
501		}
502		return buf.Bytes(), &req.Capabilities, nil
503	}
504	
505	func fetchToStoreV1(
506		ctx context.Context,
507		store storer.Storer,
508		conn Conn,
509		adv *packp.AdvRefs,
510		desired map[plumbing.ReferenceName]DesiredRef,
511		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
512		verbose bool,
513	) error {
514		body, caps, err := buildV1UploadPackBody(adv, desired, targetRefs, hasTag(desired), verbose)
515		if err != nil {
516			return err
517		}
518		reader, err := PostRPCStream(ctx, conn, transport.UploadPackService, body, false, "upload-pack fetch")
519		if err != nil {
520			return fmt.Errorf("source upload-pack: %w", err)
521		}
522		defer ioutil.CheckClose(reader, &err)
523	
524		// Decode server response (ACK/NAK) then read pack with sideband demux.
525		buffered := bufio.NewReader(reader)
526		var srvResp packp.ServerResponse
527		if decErr := srvResp.Decode(buffered); decErr != nil {
528			return fmt.Errorf("decode server response: %w", decErr)
529		}
530		if drainErr := drainTrailingNAKs(buffered); drainErr != nil {
531			return fmt.Errorf("drain server response: %w", drainErr)
532		}
533		sbReader := buildSidebandReader(caps, buffered, progressSink(verbose, "source: ", conn.ProgressWriter()))
534		if err := packfile.UpdateObjectStorage(store, sbReader); err != nil {
535			return fmt.Errorf("update object storage: %w", err)
536		}
537		return nil
538	}
