540	func fetchPackV1(
541		ctx context.Context,
542		conn Conn,
543		adv *packp.AdvRefs,
544		desired map[plumbing.ReferenceName]DesiredRef,
545		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
546		verbose bool,
547	) (io.ReadCloser, error) {
548		body, caps, err := buildV1UploadPackBody(adv, desired, targetRefs, hasTag(desired), verbose)
549		if err != nil {
550			return nil, err
551		}
552		reader, err := PostRPCStream(ctx, conn, transport.UploadPackService, body, false, "upload-pack fetch")
553		if err != nil {
554			return nil, fmt.Errorf("source upload-pack: %w", err)
555		}
556	
557		buffered := bufio.NewReader(reader)
558		var srvResp packp.ServerResponse
559		if decErr := srvResp.Decode(buffered); decErr != nil {
560			_ = reader.Close()
561			return nil, fmt.Errorf("decode server response: %w", decErr)
562		}
563		if drainErr := drainTrailingNAKs(buffered); drainErr != nil {
564			_ = reader.Close()
565			return nil, fmt.Errorf("drain server response: %w", drainErr)
566		}
567		return &wrappedRC{
568			Reader: buildSidebandReader(caps, buffered, progressSink(verbose, "source: ", conn.ProgressWriter())),
569			Closer: reader,
570		}, nil
571	}
572	
573	// drainTrailingNAKs consumes any extra "NAK\n" pktlines left in the stream
574	// after ServerResponse.Decode. go-git's upload-pack server emits a second NAK
575	// when haves were sent but none were reachable from the wants (see
576	// plumbing/transport/upload_pack.go), while go-git's ServerResponse.Decode
577	// stops after the first NAK. The remainder would otherwise be misread by the
578	// sideband demuxer as a frame with channel byte 'N' ("unknown channel NAK").
579	//
580	// A stream that runs out before we can peek 8 bytes carries no trailing NAK
581	// to drain, so we silently stop. The downstream consumer observes the same
582	// underlying read error on its first read.
583	func drainTrailingNAKs(r *bufio.Reader) error {
584		for {
585			header, err := r.Peek(8)
586			if len(header) < 8 || !bytes.Equal(header, []byte("0008NAK\n")) {
587				_ = err
588				return nil
589			}
590			if _, err := r.Discard(8); err != nil {
591				return fmt.Errorf("discard trailing NAK: %w", err)
592			}
593		}
594	}
595	
596	// buildSidebandReader wraps a reader with sideband demuxing if the negotiated
597	// capabilities include sideband support. Delegates to PreferredSideband (issue #4).
598	func buildSidebandReader(caps *capability.List, reader io.Reader, progress sideband.Progress) io.Reader {
599		sb := PreferredSideband(caps)
600		if sb == "" {
601			return reader
602		}
603		var t sideband.Type
604		if sb == capability.Sideband64k {
605			t = sideband.Sideband64k
606		} else {
607			t = sideband.Sideband
608		}
609		d := sideband.NewDemuxer(t, reader)
610		d.Progress = progress
611		return d
612	}
