614	// --- helpers ---
615	
616	func collectWants(desired map[plumbing.ReferenceName]DesiredRef) []plumbing.Hash {
617		hashes := make([]plumbing.Hash, 0, len(desired))
618		for _, ref := range desired {
619			hashes = append(hashes, ref.SourceHash)
620		}
621		return SortedUniqueHashes(hashes)
622	}
623	
624	func hasTag(desired map[plumbing.ReferenceName]DesiredRef) bool {
625		for _, ref := range desired {
626			if ref.IsTag {
627				return true
628			}
629		}
630		return false
631	}
632	
633	func refValues(m map[plumbing.ReferenceName]plumbing.Hash) []plumbing.Hash {
634		out := make([]plumbing.Hash, 0, len(m))
635		for _, h := range m {
636			if !h.IsZero() {
637				out = append(out, h)
638			}
639		}
640		return out
641	}
642	
643	// SortedUniqueHashes deduplicates and sorts a hash slice.
644	func SortedUniqueHashes(input []plumbing.Hash) []plumbing.Hash {
645		seen := make(map[plumbing.Hash]struct{}, len(input))
646		out := make([]plumbing.Hash, 0, len(input))
647		for _, h := range input {
648			if _, ok := seen[h]; ok {
649				continue
650			}
651			seen[h] = struct{}{}
652			out = append(out, h)
653		}
654		plumbing.HashesSort(out)
655		return out
656	}
