48	// BootstrapStrategy values accepted by AdvancedOptions.BootstrapStrategy.
49	// Empty is treated as the default (first-parent).
50	//
51	// BootstrapStrategyTopo additionally requires the target to allow
52	// non-fast-forward updates under the refs/gitsync/ namespace, since
53	// successive checkpoints under topological ordering aren't guaranteed
54	// to be in an ancestor-descendant relationship and the internal temp
55	// ref may receive non-ff updates between batches. Major hosts allow
56	// this by default; only locked-down deployments need to be checked.
57	const (
58		BootstrapStrategyFirstParent = "first-parent"
59		BootstrapStrategyTopo        = "topo"
60	)
61	
62	// Validate rejects unknown values up front so callers don't have to
63	// wait for the deep bootstrap planning path to surface them. It runs
64	// on every request method regardless of whether the value will end
65	// up being consulted, since silently accepting a typo on a
66	// non-bootstrap path is worse than failing fast.
67	func (o AdvancedOptions) Validate() error {
68		switch o.BootstrapStrategy {
69		case "", BootstrapStrategyFirstParent, BootstrapStrategyTopo:
70			return nil
71		default:
72			return fmt.Errorf("unsupported bootstrap strategy %q (want %q or %q)",
73				o.BootstrapStrategy, BootstrapStrategyFirstParent, BootstrapStrategyTopo)
74		}
75	}
