422	// tallyActions counts ref pushes and deletes from a classified plan slice.
423	// ActionWarn/Skip/Block don't contribute; rejections are tracked separately
424	// in Result.Warned via applyRejections.
425	func tallyActions(plans []BranchPlan) (pushed, deleted int) {
426		for _, plan := range plans {
427			switch plan.Action {
428			case ActionCreate, ActionUpdate:
429				pushed++
430			case ActionDelete:
431				deleted++
432			case ActionWarn, ActionSkip, ActionBlock:
433			}
434		}
435		return pushed, deleted
436	}
