33	// BuildDesiredRefs constructs the set of desired refs and managed targets from
34	// source refs and user configuration. All mapping validation happens here,
35	// before any network activity (issue #2, #3).
36	func BuildDesiredRefs(
37		sourceRefs map[plumbing.ReferenceName]plumbing.Hash,
38		cfg PlanConfig,
39	) (map[plumbing.ReferenceName]DesiredRef, map[plumbing.ReferenceName]ManagedTarget, error) {
40		cfg = normalizeAllRefs(cfg)
41		desired := make(map[plumbing.ReferenceName]DesiredRef)
42		managed := make(map[plumbing.ReferenceName]ManagedTarget)
43	
44		addManaged := func(sourceRef, targetRef plumbing.ReferenceName, kind RefKind, hash plumbing.Hash) error {
45			if hash.IsZero() {
46				return fmt.Errorf("source ref %s not found", sourceRef)
47			}
48			// Reject duplicate target refs from different sources (issue #2, #3).
49			if existing, ok := desired[targetRef]; ok && existing.SourceRef != sourceRef {
50				return fmt.Errorf("duplicate target ref %s: mapped from both %s and %s", targetRef, existing.SourceRef, sourceRef)
51			}
52			short := targetRef.Short()
53			desired[targetRef] = DesiredRef{
54				Kind:       kind,
55				Label:      short,
56				SourceRef:  sourceRef,
57				TargetRef:  targetRef,
58				SourceHash: hash,
59			}
60			managed[targetRef] = ManagedTarget{Kind: kind, Label: short}
61			return nil
62		}
63	
64		if len(cfg.Mappings) > 0 {
65			// Validate all mappings up front (issue #2, #3)
66			normalized, err := validation.ValidateMappings(cfg.Mappings, cfg.AllRefs)
67			if err != nil {
68				return nil, nil, fmt.Errorf("validate ref mappings: %w", err)
69			}
70			for _, nm := range normalized {
71				kind := RefKindFromName(nm.TargetRef)
72				if err := addManaged(nm.SourceRef, nm.TargetRef, kind, sourceRefs[nm.SourceRef]); err != nil {
73					return nil, nil, err
74				}
75			}
76		} else {
77			branches := BranchMapFromRefHashMap(sourceRefs)
78			selected := SelectBranches(branches, cfg.Branches)
79			for branch, hash := range selected {
80				refName := plumbing.NewBranchReferenceName(branch)
81				if IsRefExcluded(refName, cfg.ExcludeRefPrefixes) {
82					continue
83				}
84				if err := addManaged(refName, refName, RefKindBranch, hash); err != nil {
85					return nil, nil, err
86				}
87			}
88		}
89	
90		// AllRefs implies tag inclusion. Both passes (tag, other-kind) walk
91		// sourceRefs once: under AllRefs+IncludeTags this saves a redundant
92		// iteration on repos with thousands of refs/changes/* or refs/notes/*.
93		wantTags := cfg.IncludeTags || cfg.AllRefs
94		if wantTags || cfg.AllRefs {
95			for refName, hash := range sourceRefs {
96				kind := RefKindFromName(refName)
97				switch {
98				case kind == RefKindTag && wantTags:
99				case kind == RefKindOther && cfg.AllRefs:
100				default:
101					continue
102				}
103				if IsRefExcluded(refName, cfg.ExcludeRefPrefixes) {
104					continue
105				}
106				if _, ok := desired[refName]; ok {
107					continue
108				}
109				if err := addManaged(refName, refName, kind, hash); err != nil {
110					return nil, nil, err
111				}
112			}
113		}
114	
115		return desired, managed, nil
116	}
