106	// Empty prefixes are ignored. Used to subtract specific namespaces from
107	// auto-discovery (e.g. refs/pull/* under --all-refs against GitHub).
108	func IsRefExcluded(name plumbing.ReferenceName, excludePrefixes []string) bool {
109		if len(excludePrefixes) == 0 {
110			return false
111		}
