183			return nil, err
184		}
185		wantContentType := fmt.Sprintf("application/x-%s-advertisement", service)
186		gotContentType := res.Header.Get("Content-Type")
187		gotMediaType := gotContentType
188		if gotContentType != "" {
189			if mediaType, _, err := mime.ParseMediaType(gotContentType); err == nil {
190				gotMediaType = mediaType
191			}
192		}
193		if gotMediaType != wantContentType {
194			return nil, fmt.Errorf("unexpected info/refs content-type %q, want %q", gotContentType, wantContentType)
195		}
196		if c.FollowInfoRefsRedirect && res.Request != nil && res.Request.URL != nil {
197			final := res.Request.URL
198			if final.Host != c.EndpointURL.Host || final.Scheme != c.EndpointURL.Scheme {
199				c.EndpointURL.Scheme = final.Scheme
200				c.EndpointURL.Host = final.Host
201			}
202		}
203		// Bound the read to prevent unbounded memory allocation (issue #9).
204		const maxInfoRefsSize = 64 * 1024 * 1024 // 64 MiB
205		lr := io.LimitReader(res.Body, maxInfoRefsSize+1)
206		data, err := io.ReadAll(lr)
207		if err != nil {
208			return nil, fmt.Errorf("read info-refs response: %w", err)
209		}
210		if int64(len(data)) > maxInfoRefsSize {
211			return nil, fmt.Errorf("info/refs response exceeds %d byte limit", maxInfoRefsSize)
212		}
213		return data, nil
214	}
