368				return err
369			}
370		}
371	
372		if _, err = fmt.Fprint(w, "author "); err != nil {
373			return err
374		}
375	
376		if err = c.Author.Encode(w); err != nil {
377			return err
378		}
379	
380		if _, err = fmt.Fprint(w, "\ncommitter "); err != nil {
381			return err
382		}
383	
384		if err = c.Committer.Encode(w); err != nil {
385			return err
386		}
387	
388		if string(c.Encoding) != "" && c.Encoding != defaultUtf8CommitMessageEncoding {
389			if _, err = fmt.Fprintf(w, "\n%s %s", headerencoding, c.Encoding); err != nil {
390				return err
391			}
392		}
393	
394		for _, header := range c.ExtraHeaders {
395			if isStandardHeader(header.Key) {
