405				return err
406			}
407	
408			// Split all the signature lines and re-write with a left padding and
409			// newline. Use join for this so it's clear that a newline should not be
410			// added after this section, as it will be added when the message is
411			// printed.
412			signature := strings.TrimSuffix(c.Signature, "\n")
413			lines := strings.Split(signature, "\n")
414			if _, err = fmt.Fprint(w, strings.Join(lines, "\n ")); err != nil {
415				return err
416			}
417		}
418	
419		if c.SignatureSHA256 != "" && includeSig {
420			if _, err = fmt.Fprint(w, "\n"+headerpgp256+" "); err != nil {
421				return err
422			}
423	
424			signature := strings.TrimSuffix(c.SignatureSHA256, "\n")
425			lines := strings.Split(signature, "\n")
426			if _, err = fmt.Fprint(w, strings.Join(lines, "\n ")); err != nil {
427				return err
428			}
429		}
430	
431		if _, err = fmt.Fprintf(w, "\n\n%s", c.Message); err != nil {
432			return err
433		}
434	
435		return err
436	}
