func openSource(ctx context.Context, req Request) (gitproto.Conn, *gitproto.RefService, error) {
	ep, err := url.Parse(req.SourceURL)
	if err != nil {
		return nil, nil, fmt.Errorf("parse source URL: %w", err)
	}
	if ep.Scheme != "http" && ep.Scheme != "https" {
		return nil, nil, fmt.Errorf("convert-sha256 currently supports HTTP/HTTPS sources only; got %q", ep.Scheme)
	}
	authMethod, err := auth.Resolve(auth.Endpoint{
		Username:      req.SourceAuth.Username,
		Token:         req.SourceAuth.Token,
		BearerToken:   req.SourceAuth.BearerToken,
		SkipTLSVerify: req.SourceAuth.SkipTLSVerify,
	}, ep)
	if err != nil {
		return nil, nil, fmt.Errorf("resolve source auth: %w", err)
	}
	httpClient := &http.Client{Transport: gitproto.NewHTTPTransport(req.SourceAuth.SkipTLSVerify)}
	conn := gitproto.NewHTTPConnWithClient(ep, "source", normalizeAuth(authMethod), httpClient)
	conn.FollowInfoRefsRedirect = req.SourceFollowInfoRefsRedirect

	mode := string(req.ProtocolMode)
	if mode == "" {
		mode = string(gitsync.ProtocolAuto)
	}

	planCfg := planner.PlanConfig{
		Branches:           req.Branches,
		Mappings:           toPlannerMappings(req.Mappings),
		IncludeTags:        req.IncludeTags,
		AllRefs:            req.AllRefs,
		ExcludeRefPrefixes: req.ExcludeRefPrefixes,
	}
	prefixes := planner.RefPrefixes(planCfg)

	_, svc, err := gitproto.ListSourceRefs(ctx, conn, mode, prefixes)
	if err != nil {
		_ = conn.Close()
		return nil, nil, fmt.Errorf("list source refs: %w", err)
	}
	return conn, svc, nil
}

// refServiceRefsMap collapses the ref list inside the negotiated RefService
// back into the (name → hash) map the planner expects. For v2, the refs
// were already returned by ListSourceRefs and discarded by openSource —
// rather than thread them through, we ls-refs once more here. Source ref
// discovery is cheap relative to the pack fetch.
func refServiceRefsMap(ctx context.Context, conn gitproto.Conn, svc *gitproto.RefService) (map[plumbing.ReferenceName]plumbing.Hash, error) {
	switch svc.Protocol {
	case "v1":
		refs, err := gitproto.AdvRefsToSlice(svc.V1Adv)
		if err != nil {
			return nil, fmt.Errorf("decode v1 refs: %w", err)
		}
		return gitproto.RefHashMap(refs), nil
	case "v2":
		// V2Capabilities doesn't cache the ref list, so re-issue ls-refs.
		// The "refs/" prefix mirrors planner.RefPrefixes under AllRefs.
		refs, err := gitproto.ListSourceRefsV2(ctx, conn, svc.V2Caps, []string{"refs/"})
		if err != nil {
			return nil, fmt.Errorf("ls-refs v2: %w", err)
		}
		return gitproto.RefHashMap(refs), nil
	default:
		return nil, fmt.Errorf("unsupported protocol %q", svc.Protocol)
	}
}

