func (t *translator) translateBlob(sha1 plumbing.Hash, src plumbing.EncodedObject) (plumbing.Hash, error) {
	dstObj := t.dst.NewEncodedObject()
	dstObj.SetType(plumbing.BlobObject)
	w, err := dstObj.Writer()
	if err != nil {
		return plumbing.ZeroHash, fmt.Errorf("blob writer: %w", err)
	}
	r, err := src.Reader()
	if err != nil {
		return plumbing.ZeroHash, fmt.Errorf("blob reader: %w", err)
	}
	if _, err := io.Copy(w, r); err != nil {
		_ = w.Close()
		_ = r.Close()
		return plumbing.ZeroHash, fmt.Errorf("blob copy: %w", err)
	}
	if err := w.Close(); err != nil {
		_ = r.Close()
		return plumbing.ZeroHash, fmt.Errorf("blob close: %w", err)
	}
	if err := r.Close(); err != nil {
		return plumbing.ZeroHash, fmt.Errorf("blob src close: %w", err)
	}
	newHash, err := t.dst.SetEncodedObject(dstObj)
	if err != nil {
		return plumbing.ZeroHash, fmt.Errorf("blob store: %w", err)
	}
	t.mapping[sha1] = newHash
	t.counts.Blobs++
	return newHash, nil
}

