104	// Run performs the conversion described by req.
105	func Run(ctx context.Context, req Request) (Result, error) {
106		if req.SourceURL == "" {
107			return Result{}, errors.New("convert-sha256 requires --source-url")
108		}
109		if req.TargetDir == "" {
110			return Result{}, errors.New("convert-sha256 requires a target directory")
111		}
112		out := req.Out
113		if out == nil {
114			out = os.Stderr
115		}
116	
117		if err := ensureEmptyTarget(req.TargetDir); err != nil {
118			return Result{}, err
119		}
120	
121		tempDir, err := os.MkdirTemp("", "git-sync-sha256-src-")
122		if err != nil {
123			return Result{}, fmt.Errorf("create temp dir: %w", err)
124		}
125		cleanupTemp := true
126		defer func() {
127			if cleanupTemp {
128				_ = os.RemoveAll(tempDir)
129			}
130		}()
131	
132		srcRepo, err := git.PlainInit(tempDir, true)
133		if err != nil {
134			return Result{}, fmt.Errorf("init temporary SHA1 store: %w", err)
135		}
136	
137		dstRepo, err := git.PlainInit(req.TargetDir, true, git.WithObjectFormat(formatcfg.SHA256))
138		if err != nil {
139			return Result{}, fmt.Errorf("init SHA256 target at %s: %w", req.TargetDir, err)
140		}
141	
142		// Source connection + ref discovery -----------------------------------
143		planCfg := planner.PlanConfig{
144			Branches:           append([]string(nil), req.Branches...),
145			Mappings:           toPlannerMappings(req.Mappings),
146			IncludeTags:        req.IncludeTags,
147			AllRefs:            req.AllRefs,
148			ExcludeRefPrefixes: append([]string(nil), req.ExcludeRefPrefixes...),
149		}

150		conn, refService, sourceRefList, err := openSource(ctx, req, planCfg)
151		if err != nil {
152			return Result{}, err
153		}
154		defer conn.Close()
155		refService.Verbose = req.Verbose
156	
157		sourceRefs := gitproto.RefHashMap(sourceRefList)
158		desired, _, err := planner.BuildDesiredRefs(sourceRefs, planCfg)
159		if err != nil {
160			return Result{}, fmt.Errorf("build desired refs: %w", err)
161		}
162		if len(desired) == 0 {
163			return Result{}, errors.New("no source refs matched the requested scope")
164		}
165	
166		// Fetch into temp SHA1 store ------------------------------------------
167		fmt.Fprintf(out, "fetching %d ref(s) from %s ...\n", len(desired), req.SourceURL)
168		gpDesired := convert.DesiredRefs(desired)
169		if err := refService.FetchToStore(ctx, srcRepo.Storer, conn, gpDesired, nil); err != nil &&
170			!errors.Is(err, git.NoErrAlreadyUpToDate) {
171			return Result{}, fmt.Errorf("fetch source pack: %w", err)
172		}
173	
174		// Translate ----------------------------------------------------------
175		fmt.Fprintln(out, "translating objects to sha256 ...")
176		tr, err := newTranslator(srcRepo.Storer, dstRepo.Storer, req.TargetDir)
177		if err != nil {
178			return Result{}, err
179		}
180		for _, d := range desired {
181			if _, err := tr.translate(d.SourceHash); err != nil {
182				return Result{}, fmt.Errorf("translate %s: %w", d.SourceRef, err)
183			}
184		}
185	
186		// Write refs ---------------------------------------------------------
187		refsWritten, err := writeRefs(dstRepo.Storer, desired, tr.mapping)
188		if err != nil {
189			return Result{}, fmt.Errorf("write target refs: %w", err)
190		}
191	
192		// Point HEAD at the source's symbolic HEAD if it landed in the
193		// converted ref set. PlainInit defaults HEAD to refs/heads/master,
194		// which often doesn't exist (e.g. repos using "main" as the default).
195		if refService.HeadTarget != "" {
196			if _, ok := desired[refService.HeadTarget]; ok {
197				head := plumbing.NewSymbolicReference(plumbing.HEAD, refService.HeadTarget)
198				if err := dstRepo.Storer.SetReference(head); err != nil {
199					return Result{}, fmt.Errorf("set HEAD: %w", err)
200				}
201			}
202		}
203	
204		res := Result{
205			SourceURL:          req.SourceURL,
206			TargetDir:          req.TargetDir,
207			Protocol:           refService.Protocol,
208			RefsConverted:      refsWritten,
209			Counts:             tr.counts,
210			SignaturesStripped: tr.signaturesStripped,
211		}
212		if req.KeepSourceObjects {
213			cleanupTemp = false
214			res.TempDir = tempDir
215		}
216		return res, nil
217	}
