299	// translator walks the SHA1 source store, rewrites object content with
300	// SHA256-mapped hashes, and writes the result as loose objects under the
301	// target bare repo. Loose object writing is done by hand because go-git
302	// v6 alpha 3's objfile.Writer hardcodes SHA1 in prepareForWrite (see
303	// plumbing/format/objfile/writer.go:68), which would store every SHA256
304	// object at a SHA1-derived path.
305	type translator struct {
306		src                *filesystem.Storage
307		dst                *filesystem.Storage
308		objectsDir         string
309		mapping            map[plumbing.Hash]plumbing.Hash
310		counts             Counts
311		signaturesStripped int
312	}
313	
314	func newTranslator(src, dst storer.Storer, targetDir string) (*translator, error) {
315		srcFS, ok := src.(*filesystem.Storage)
316		if !ok {
317			return nil, fmt.Errorf("source storage is not filesystem-backed (%T)", src)
318		}
319		dstFS, ok := dst.(*filesystem.Storage)
320		if !ok {
321			return nil, fmt.Errorf("target storage is not filesystem-backed (%T)", dst)
322		}
323		return &translator{
324			src:        srcFS,
325			dst:        dstFS,
326			objectsDir: filepath.Join(targetDir, "objects"),
327			mapping:    make(map[plumbing.Hash]plumbing.Hash),
328		}, nil
329	}
330	
331	func (t *translator) translate(sha1 plumbing.Hash) (plumbing.Hash, error) {
332		if newH, ok := t.mapping[sha1]; ok {
333			return newH, nil
334		}
335		obj, err := t.src.EncodedObject(plumbing.AnyObject, sha1)
336		if err != nil {
337			return plumbing.ZeroHash, fmt.Errorf("lookup %s: %w", sha1, err)
338		}
339		switch obj.Type() {
340		case plumbing.BlobObject:
341			return t.translateBlob(sha1, obj)
342		case plumbing.TreeObject:
343			return t.translateTree(sha1, obj)
344		case plumbing.CommitObject:
345			return t.translateCommit(sha1, obj)
346		case plumbing.TagObject:
347			return t.translateTag(sha1, obj)
348		default:
349			return plumbing.ZeroHash, fmt.Errorf("unexpected object type %v for %s", obj.Type(), sha1)
350		}
351	}
352	
353	func (t *translator) translateBlob(sha1 plumbing.Hash, src plumbing.EncodedObject) (plumbing.Hash, error) {
354		r, err := src.Reader()
355		if err != nil {
356			return plumbing.ZeroHash, fmt.Errorf("blob reader: %w", err)
357		}
358		defer r.Close()
359		body, err := io.ReadAll(r)
360		if err != nil {
361			return plumbing.ZeroHash, fmt.Errorf("blob read: %w", err)
362		}
363		newHash, err := t.writeLoose(plumbing.BlobObject, body)
364		if err != nil {
365			return plumbing.ZeroHash, fmt.Errorf("blob store: %w", err)
366		}
367		t.mapping[sha1] = newHash
368		t.counts.Blobs++
369		return newHash, nil
370	}
371	
372	func (t *translator) translateTree(sha1 plumbing.Hash, src plumbing.EncodedObject) (plumbing.Hash, error) {
373		tree := &object.Tree{}
374		if err := tree.Decode(src); err != nil {
375			return plumbing.ZeroHash, fmt.Errorf("decode tree %s: %w", sha1, err)
376		}
377		for i, entry := range tree.Entries {
378			if entry.Mode == filemode.Submodule {
379				// Submodule gitlinks reference a commit in a different repo.
380				// We can only translate if that commit happens to live in our
381				// SHA1 store too (rare, e.g. vendored). Otherwise the SHA1
382				// pointer can't be embedded in a SHA256 tree, so we error
383				// out and let the caller scope around it.
384				if _, ok := t.mapping[entry.Hash]; ok {
385					tree.Entries[i].Hash = t.mapping[entry.Hash]
386					continue
387				}
388				if _, err := t.src.EncodedObject(plumbing.CommitObject, entry.Hash); err == nil {
389					newH, err := t.translate(entry.Hash)
390					if err != nil {
391						return plumbing.ZeroHash, err
392					}
393					tree.Entries[i].Hash = newH
394					continue
395				}
396				return plumbing.ZeroHash, fmt.Errorf(
397					"tree %s contains submodule gitlink %q at %s that is not present in the source repo; "+
398						"exclude refs that reference it or convert the submodule repository first",
399					sha1, entry.Name, entry.Hash)

400			}
401			newH, err := t.translate(entry.Hash)
402			if err != nil {
403				return plumbing.ZeroHash, fmt.Errorf("tree %s entry %q: %w", sha1, entry.Name, err)
404			}
405			tree.Entries[i].Hash = newH
406		}
407		body, err := encodeBody(plumbing.TreeObject, tree.Encode)
408		if err != nil {
409			return plumbing.ZeroHash, fmt.Errorf("encode tree %s: %w", sha1, err)
410		}
411		newHash, err := t.writeLoose(plumbing.TreeObject, body)
412		if err != nil {
413			return plumbing.ZeroHash, fmt.Errorf("store tree %s: %w", sha1, err)
414		}
415		t.mapping[sha1] = newHash
416		t.counts.Trees++
417		return newHash, nil
418	}
419	
420	func (t *translator) translateCommit(sha1 plumbing.Hash, src plumbing.EncodedObject) (plumbing.Hash, error) {
421		c := &object.Commit{}
422		if err := c.Decode(src); err != nil {
423			return plumbing.ZeroHash, fmt.Errorf("decode commit %s: %w", sha1, err)
424		}
425		newTree, err := t.translate(c.TreeHash)
426		if err != nil {
427			return plumbing.ZeroHash, fmt.Errorf("commit %s tree: %w", sha1, err)
428		}
429		c.TreeHash = newTree
430		for i, p := range c.ParentHashes {
431			newP, err := t.translate(p)
432			if err != nil {
433				return plumbing.ZeroHash, fmt.Errorf("commit %s parent %s: %w", sha1, p, err)
434			}
