// hashPattern matches hex runs that could be a git object hash. Git's
// default abbreviation is 7 chars; 40 is a full SHA1. We only rewrite a
// match if the prefix uniquely identifies an entry in our SHA1 mapping,
// so false positives on incidental hex strings are essentially impossible
// (a random hex would have to collide with a real source SHA1).
var hashPattern = regexp.MustCompile(`\b[0-9a-f]{7,40}\b`)

// rewriteHashesInMessage scans msg for short and full SHA1 hashes, replacing
// any that uniquely match a SHA1 in t.mapping with the corresponding full
// SHA256 hex. Returns the rewritten message and the substitution count.
//
// Performance: the abbreviated-hash path scans the mapping linearly for
// each match. Fine for repos up to ~100k commits; slower past that. If
// this ever matters, build a sorted-prefix index once and binary-search.
func (t *translator) rewriteHashesInMessage(msg string) (string, int) {
	count := 0
	out := hashPattern.ReplaceAllStringFunc(msg, func(s string) string {
		newHex, ok := t.lookupSHA1Prefix(s)
		if !ok {
			return s
		}
		count++
		return newHex
	})
	return out, count
}

func (t *translator) lookupSHA1Prefix(prefix string) (string, bool) {
	if len(prefix) == 40 {
		sha1, ok := plumbing.FromHex(prefix)
		if !ok {
			return "", false
		}
		if newHash, ok := t.mapping[sha1]; ok {
			return newHash.String(), true
		}
		return "", false
	}
	var match plumbing.Hash
	matches := 0
	for sha1, sha256 := range t.mapping {
		if strings.HasPrefix(sha1.String(), prefix) {
			matches++
			if matches > 1 {
				return "", false
			}
			match = sha256
		}
	}
	if matches != 1 {
		return "", false
	}
	return match.String(), true
}

